		'supports'     => [ 'title', 'editor', 'thumbnail', 'excerpt', 'page-attributes' ],
		'menu_icon'    => 'dashicons-art',
		'rewrite'      => [ 'slug' => 'portfolio/branding' ],
		'template'     => [
			[ 'core/heading', [ 'level' => 3, 'content' => 'O projekcie', 'placeholder' => 'Nagłówek sekcji' ] ],
			[ 'core/paragraph', [ 'placeholder' => 'Opisz tutaj projekt — brief klienta, wyzwania, kontekst...' ] ],
			[ 'core/image', [ 'alt' => 'Screenshot / wizualizacja projektu' ] ],
			[ 'core/heading', [ 'level' => 3, 'content' => 'Proces i rozwiązania', 'placeholder' => 'Nagłówek sekcji' ] ],
			[ 'core/paragraph', [ 'placeholder' => 'Opisz tutaj proces projektowania, decyzje designerskie, efekty...' ] ],
			[ 'core/gallery', [] ],
		],
	] );

	// Dodaj istniejącą taksonomię do nowego CPT (CPT-UI rejestruje ją wcześniej na init 10)
	register_taxonomy_for_object_type( 'rodzaj-realizacji', 'branding' );
}, 11 );

// =========================================================
// Portfolio grid: dodaj branding do zapytania Kadence block
// =========================================================
add_filter( 'kadence_blocks_pro_portfolio_grid_query_args', function ( $args, $attributes ) {
	if ( is_page( 'portfolio' ) && isset( $args['post_type'] ) && 'moja_realizacja' === $args['post_type'] ) {
		$args['post_type'] = [ 'moja_realizacja', 'branding' ];
	}
	return $args;
}, 10, 2 );

// =========================================================
// Enqueue branding-single.css tylko na stronach brandingu
// =========================================================
add_action( 'wp_enqueue_scripts', function () {
	if ( is_singular( 'branding' ) ) {
		wp_enqueue_style(
			'mybeeweb-branding-single',
			get_stylesheet_directory_uri() . '/branding-single.css',
			[ 'kadence-global' ],
			wp_get_theme()->get( 'Version' )
		);
	}
}, 20 );
